const body = $input.first().json.body;

if (!body?.campaign_id) {
  throw new Error('campaign_id missing');
}

const supabaseUrl = 'https://jncmizoejeaclpnfxazg.supabase.co';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImpuY21pem9lamVhY2xwbmZ4YXpnIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NzEzMTczMiwiZXhwIjoyMDkyNzA3NzMyfQ.A8A4tMGzUFuhH4DOSb77QByuKmNdajZ_kCRvr_yxqFo';

try {
  // 1. Mark campaign as sending
  await this.helpers.request({
    method: 'PATCH',
    url: `${supabaseUrl}/rest/v1/campaigns?id=eq.${body.campaign_id}`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json'
    },
    body: {
      status: 'sending',
      started_at: new Date().toISOString()
    },
    json: true
  });

  // 2. Fetch the campaign's org_id
  const campaigns = await this.helpers.request({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/campaigns?id=eq.${body.campaign_id}&select=org_id`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`
    },
    json: true
  });

  const orgId = campaigns[0]?.org_id;
  if (!orgId) {
    throw new Error('org_id not found for campaign');
  }

  // 3. Fetch organization settings for this org_id
  const settingsList = await this.helpers.request({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/organization_settings?org_id=eq.${orgId}`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`
    },
    json: true
  });

  const settings = settingsList[0];
  if (!settings?.whatsapp_token || !settings?.whatsapp_phone_id) {
    throw new Error('WhatsApp settings not configured for this organization');
  }

  return [{
    json: {
      campaign_id: body.campaign_id,
      template_name: body.template_name,
      header_image_url: body.header_image_url || '',
      contacts: body.contacts,
      whatsapp_token: settings.whatsapp_token,
      whatsapp_phone_id: settings.whatsapp_phone_id,
      whatsapp_waba_id: settings.whatsapp_waba_id || '',
      supabase_url: supabaseUrl,
      supabase_key: supabaseKey
    }
  }];
} catch (error) {
  throw new Error(`Mark campaign sending failed: ${error.message}`);
}

const contact = $json;
const settings = $('Mark Campaign Sending').first().json;

let metaMediaId = null;
try {
  metaMediaId = $('Upload to Meta').first().json.id;
} catch (e) {
  // Upload to Meta node was skipped (no media)
}

const components = [];

if (settings.header_image_url && settings.header_image_url.trim() !== '') {
  const url = settings.header_image_url.trim();
  const isPdf = url.toLowerCase().includes('.pdf');

  if (metaMediaId) {
    if (isPdf) {
      components.push({
        type: 'header',
        parameters: [
          {
            type: 'document',
            document: {
              id: metaMediaId,
              filename: url.split('/').pop() || 'document.pdf'
            }
          }
        ]
      });
    } else {
      components.push({
        type: 'header',
        parameters: [
          {
            type: 'image',
            image: {
              id: metaMediaId
            }
          }
        ]
      });
    }
  } else {
    if (isPdf) {
      components.push({
        type: 'header',
        parameters: [
          {
            type: 'document',
            document: {
              link: url,
              filename: url.split('/').pop() || 'document.pdf'
            }
          }
        ]
      });
    } else {
      components.push({
        type: 'header',
        parameters: [
          {
            type: 'image',
            image: {
              link: url
            }
          }
        ]
      });
    }
  }
}

if (contact.variables && typeof contact.variables === 'object') {
  const params = [];
  const keys = Object.keys(contact.variables).sort((a, b) => {
    const numA = parseInt(a.replace(/\D/g, '')) || 0;
    const numB = parseInt(b.replace(/\D/g, '')) || 0;
    return numA - numB;
  });

  for (const k of keys) {
    params.push({
      type: 'text',
      text: String(contact.variables[k])
    });
  }

  if (params.length > 0) {
    components.push({
      type: 'body',
      parameters: params
    });
  }
}

const payload = {
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: contact.phone,
  type: 'template',
  template: {
    name: settings.template_name,
    language: {
      code: 'en'
    }
  }
};

if (components.length > 0) {
  payload.template.components = components;
}

return {
  json: {
    contact_phone: contact.phone,
    contact_name: contact.name,
    campaign_id: settings.campaign_id,
    whatsapp_token: settings.whatsapp_token,
    whatsapp_phone_id: settings.whatsapp_phone_id,
    supabase_url: settings.supabase_url,
    supabase_key: settings.supabase_key,
    payload: payload
  }
};

const response = $json;
const buildPayloadNode = $('Build Payload').item;
const contactPhone = buildPayloadNode.json.contact_phone;
const campaignId = buildPayloadNode.json.campaign_id;

let status = 'failed';
let wamid = null;
let errorMsg = null;

const responseBody = response.body || response || {};
const hasMessages = responseBody.messages?.[0]?.id || response.messages?.[0]?.id;

if (hasMessages) {
  status = 'sent';
  wamid = responseBody.messages?.[0]?.id || response.messages?.[0]?.id;
} else {
  status = 'failed';
  const errorObj = responseBody.error || response.error;
  errorMsg = errorObj?.message || 'Unknown Meta API error';
}

return {
  json: {
    campaign_id: campaignId,
    phone: contactPhone,
    status: status,
    wamid: wamid,
    error: errorMsg,
    sent_at: new Date().toISOString()
  }
};

const items = $input.all();
if (items.length === 0) return [];

const settings = $('Mark Campaign Sending').first().json;
const supabaseUrl = settings.supabase_url;
const supabaseKey = settings.supabase_key;
const campaignId = settings.campaign_id;

const rows = items.map(item => ({
  campaign_id: item.json.campaign_id,
  phone: item.json.phone,
  status: item.json.status,
  wamid: item.json.wamid,
  error: item.json.error,
  sent_at: item.json.sent_at
}));

const chunks = [];
for (let i = 0; i < rows.length; i += 100) {
  chunks.push(rows.slice(i, i + 100));
}

let sent = 0;
let failed = 0;
const total = rows.length;

for (const chunk of chunks) {
  try {
    await this.helpers.request({
      method: 'POST',
      url: `${supabaseUrl}/rest/v1/campaign_contacts?on_conflict=campaign_id,phone`,
      headers: {
        apikey: supabaseKey,
        Authorization: `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
        Prefer: 'resolution=merge-duplicates'
      },
      body: chunk,
      json: true
    });

    for (const r of chunk) {
      if (r.status === 'sent') sent++;
      else failed++;
    }
  } catch (error) {
    console.error('Supabase batch upsert failed for chunk:', error);
    failed += chunk.length;
  }
}

try {
  const countsRes = await this.helpers.request({
    method: 'GET',
    url: `${supabaseUrl}/rest/v1/campaign_contacts?campaign_id=eq.${campaignId}&select=status`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`
    },
    json: true
  });

  const currentSent = countsRes.filter(c => c.status === 'sent').length;
  const currentDelivered = countsRes.filter(c => c.status === 'delivered').length;
  const currentFailed = countsRes.filter(c => c.status === 'failed').length;
  const currentPending = countsRes.filter(c => c.status === 'pending').length;

  const isCompleted = currentPending === 0;

  await this.helpers.request({
    method: 'PATCH',
    url: `${supabaseUrl}/rest/v1/campaigns?id=eq.${campaignId}`,
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json'
    },
    body: {
      sent: currentSent,
      delivered: currentDelivered,
      failed: currentFailed,
      status: isCompleted ? 'completed' : 'sending',
      completed_at: isCompleted ? new Date().toISOString() : null
    },
    json: true
  });
} catch (error) { 
  console.error('Failed to recalculate campaign status:', error);
}

return [{ 
  json: {
    success: true,
    campaign_id: campaignId,
    sent,
    failed,
    total
  }
}];
